                self.path_validation_result = result
            if status == 'ok':
                logger.debug(f"   Path validation: {message}")
            elif status == 'fail':
                issues = result.get('issues_found', 'unknown') if isinstance(result, dict) else 'unknown'
                logger.debug(f"   Path validation: {message}")
