                if len(parts) == 2:
                    summary['report_path'] = parts[1].strip()
        return summary

    def _load_mtime_cached_tool_results(
        self, 
        tool_name: str, 
        domain: str, 
        result: dict,
        parse_output_func: Callable[[str], dict[str, Any]] | None = None,
        cache_converter_func: Callable[[dict[str, Any]], dict[str, Any]] | None = None
    ) -> dict[str, Any]:
        """
        Unified helper for loading results from mtime-cached tools.

        After tool execution, this method:
        1. Loads from cache FIRST (fresh data after tool execution)
        2. Converts cache format to results format (using converter or default)
        3. Saves to results JSON
        4. Returns results dict
        5. Falls back to parsing output if cache fails
        """
        from ..output_storage import save_tool_result, load_tool_cache

        # Step 1: Load from cache FIRST using standardized storage
        cache_data = None
        try:
            cache_data = load_tool_cache(tool_name, domain, project_root=self.project_root)
            if cache_data:
                logger.debug(f"Loaded {tool_name} from cache (fresh data after execution)")
        except Exception as cache_error:
            logger.debug(f"Failed to load {tool_name} from cache: {cache_error}")

        # Step 2: Convert cache format to results format (standard format)
        if cache_data and isinstance(cache_data, dict):
            # Handle both formats: wrapped {'data': {...}} and direct {file_path: {...}}
            if 'data' in cache_data:
                file_data = cache_data.get('data', {})
            else:
                # Direct format - cache_data IS the file data
                file_data = cache_data
            if file_data and isinstance(file_data, dict):
                # CRITICAL: Filter out entries for files that no longer exist
                # The cache may contain entries for deleted files, which would cause stale data
                filtered_file_data = {}
                for file_path_str, file_info in file_data.items():
                    if isinstance(file_info, dict):
                        # Check if file still exists
                        try:
                            file_path = self.project_root / file_path_str
                            if file_path.exists():
                                # Verify mtime matches (file hasn't been modified)
                                cached_mtime = file_info.get('mtime')
                                if cached_mtime is not None:
                                    current_mtime = file_path.stat().st_mtime
                                    if current_mtime == cached_mtime:
                                        filtered_file_data[file_path_str] = file_info
                                    else:
                                        logger.debug(f"Skipping {file_path_str} - mtime mismatch (file modified)")
                                else:
                                    # No mtime in cache, include it but it will be re-scanned
                                    filtered_file_data[file_path_str] = file_info
                            else:
                                logger.debug(f"Skipping {file_path_str} - file no longer exists")
                        except (OSError, ValueError) as e:
                            logger.debug(f"Skipping {file_path_str} - error checking file: {e}")
                    else:
                        # Invalid format, skip
                        logger.debug(f"Skipping {file_path_str} - invalid cache entry format")

                # Use filtered data
                file_data = filtered_file_data
                # Use custom converter if provided, otherwise use default
                if cache_converter_func:
                    raw_result = cache_converter_func(file_data)
                else:
                    # Default converter (raw, pre-standard)
                    files_with_issues = {}
                    total_issues = 0
                    for file_path, file_info in file_data.items():
                        if isinstance(file_info, dict):
                            results = file_info.get('results', [])
                            if results:
                                files_with_issues[file_path] = len(results)
                                total_issues += len(results)
                    raw_result = {
                        'files': files_with_issues,
                        'file_count': len(files_with_issues),
                        'total_issues': total_issues
                    }

                # Ensure standard format with summary/details
                tool_result = raw_result
                if not (isinstance(raw_result, dict) and isinstance(raw_result.get('summary'), dict)):
                    files_with_issues = raw_result.get('files', {}) if isinstance(raw_result, dict) else {}
                    file_count = raw_result.get('file_count')
                    if not isinstance(file_count, int):
                        file_count = len(files_with_issues) if isinstance(files_with_issues, dict) else 0
                    total_issues = raw_result.get('total_issues', 0) if isinstance(raw_result, dict) else 0
                    tool_result = self._create_standard_format_result(
                        total_issues,
                        file_count,
                        files_with_issues if isinstance(files_with_issues, dict) else {},
                        raw_result if isinstance(raw_result, dict) else {}
                    )

                # Step 3: Save to results JSON and populate in-memory cache
                try:
                    save_tool_result(tool_name, domain, tool_result, project_root=self.project_root)
                    logger.debug(f"Regenerated {tool_name}_results.json from fresh cache")
                    # Populate in-memory cache for current audit run
                    if not hasattr(self, 'results_cache'):
                        self.results_cache = {}
                    self.results_cache[tool_name] = tool_result
                except Exception as save_error:
                    logger.debug(f"Failed to save {tool_name} results: {save_error}")

                return tool_result

        # Step 4: Fallback to parsing output if cache failed
        if result.get('output') or result.get('success'):
            if parse_output_func:
                tool_result = parse_output_func(result.get('output', ''))
                if isinstance(tool_result, dict) and 'summary' not in tool_result:
                    files_with_issues = tool_result.get('files', {})
                    file_count = tool_result.get('file_count', len(files_with_issues) if isinstance(files_with_issues, dict) else 0)
                    total_issues = tool_result.get('total_issues', 0)
                    tool_result = self._create_standard_format_result(
                        total_issues,
                        file_count,
                        files_with_issues if isinstance(files_with_issues, dict) else {},
                        tool_result
                    )
                try:
                    save_tool_result(tool_name, domain, tool_result, project_root=self.project_root)
                    logger.debug(f"Saved {tool_name} results from parsed output")
                    # Populate in-memory cache for current audit run
                    if not hasattr(self, 'results_cache'):
                        self.results_cache = {}
                    self.results_cache[tool_name] = tool_result
                except Exception as save_error:
                    logger.debug(f"Failed to save {tool_name} results: {save_error}")
                return tool_result
            else:
                logger.warning(f"No parser function provided for {tool_name}, cannot parse output")
        else:
            logger.warning(f"{tool_name} failed: {result.get('error', 'Unknown error')}")

        # Return empty result if all else fails
        return {
            'files': {},
            'file_count': 0,
            'total_issues': 0
        }

import copy

import pytest

from core.schemas import (

    validate_account_dict,
    validate_preferences_dict,
    validate_schedules_dict,
    validate_messages_file_dict,
)

pytestmark = [pytest.mark.core]



@pytest.fixture()
def base_account_data():
    return {
        "user_id": "user-123",
        "internal_username": "tester",
        "email": "not-an-email",
        "features": {
            "automated_messages": True,
            "checkins": "yes",
            "task_management": "no",
        },
    }


@pytest.mark.unit
@pytest.mark.core
def test_validate_account_dict_coerces_features_and_normalizes_email(base_account_data):
    normalized, errors = validate_account_dict(base_account_data)

    assert errors == []
    assert normalized["email"] == ""
    assert normalized["features"] == {
        "automated_messages": "enabled",
        "checkins": "enabled",
        "task_management": "disabled",
    }


@pytest.mark.unit
@pytest.mark.core
def test_validate_account_dict_reports_errors_when_required_fields_missing(base_account_data):
    incomplete = copy.deepcopy(base_account_data)
    incomplete.pop("user_id")

    normalized, errors = validate_account_dict(incomplete)

    assert errors, "Expected validation errors for missing required fields"
    assert normalized["features"]["automated_messages"] == "enabled"
    assert normalized["features"]["checkins"] == "enabled"
    assert normalized["features"]["task_management"] == "disabled"


@pytest.mark.unit
@pytest.mark.core
def test_validate_preferences_dict_retains_original_on_error():
    # Invalid category should trigger a validation error and return original payload
    prefs = {
        "categories": ["unknown_category"],
        "channel": {"type": "email", "contact": "user@example.com"},
        "checkin_settings": None,
    }

    normalized, errors = validate_preferences_dict(prefs)

    assert errors
    assert normalized == prefs


@pytest.mark.unit
@pytest.mark.core
def test_validate_schedules_dict_normalizes_days_and_times():
    schedules = {
        "motivational": {
            "periods": {
                "morning": {
                    "active": True,
                    "days": ["Monday", "Funday"],
                    "start_time": "25:00",  # invalid
                    "end_time": "06:30",
                },
                "evening": {
                    "active": False,
                    "days": [],
                    "start_time": "18:30",
                    "end_time": "not-a-time",
                },
            }
        }
    }

    normalized, errors = validate_schedules_dict(schedules)

    assert errors == []
    periods = normalized["motivational"]["periods"]
    assert periods["morning"]["days"] == ["Monday"]
    assert periods["morning"]["start_time"] == "00:00"
    assert periods["evening"]["days"] == ["ALL"]
    assert periods["evening"]["end_time"] == "00:00"


@pytest.mark.unit
@pytest.mark.core
def test_validate_messages_file_dict_filters_invalid_entries():
    data = {
        "messages": [
            {"message_id": "1", "message": "Hello!", "days": [], "time_periods": []},
            {"message": "Missing id"},
            "not-a-dict",
        ]
    }

    normalized, errors = validate_messages_file_dict(data)

    assert errors
    assert normalized["messages"] == [
        {"message_id": "1", "message": "Hello!", "days": ["ALL"], "time_periods": ["ALL"], "timestamp": None}
    ]

import copy

import pytest

from core.schemas import (

    validate_account_dict,
    validate_messages_file_dict,
    validate_preferences_dict,
    validate_schedules_dict,
)

pytestmark = [pytest.mark.core]



@pytest.mark.unit
@pytest.mark.smoke
@pytest.mark.regression
@pytest.mark.parametrize(
    "features,expected_checkins",
    [
        ({"automated_messages": True, "checkins": "yes", "task_management": 0}, "enabled"),
        ({"automated_messages": "enabled", "checkins": "no", "task_management": False}, "disabled"),
    ],
)
@pytest.mark.core
def test_validate_account_dict_normalizes_features_when_validation_fails(features, expected_checkins):
    bad_account = {
        # Missing required user_id triggers validation error path
        "internal_username": "tester",
        "features": features,
        "extra_field": "preserve",
    }

    normalized, errors = validate_account_dict(copy.deepcopy(bad_account))

    assert errors, "Validation errors should be reported when required fields are missing"
    assert normalized["features"] == {
        "automated_messages": "enabled",
        "checkins": expected_checkins,
        "task_management": "disabled",
    }
    assert normalized.get("extra_field") == "preserve"


@pytest.mark.unit
@pytest.mark.regression
@pytest.mark.core
def test_validate_preferences_dict_reports_errors_and_returns_original(monkeypatch):
    monkeypatch.setattr("core.message_management.get_message_categories", lambda: ["allowed"])
    data = {
        "categories": ["invalid"],
        "channel": {"type": "email", "contact": "user@example.com"},
        "checkin_settings": None,
        "extra": "keep",
    }

    normalized, errors = validate_preferences_dict(copy.deepcopy(data))

    assert errors, "Invalid categories should surface as validation errors"
    assert normalized == data, "On validation failure the original payload should be returned"


@pytest.mark.unit
@pytest.mark.regression
@pytest.mark.core
def test_validate_schedules_dict_normalizes_compatibility_shape_and_invalid_fields():
    compatibility_shape = {
        "general": {
            "morning": {
                "days": ["Funday", "ALL"],
                "start_time": "99:00",
                "end_time": "not-a-time",
                "unexpected": "ignore",
            }
        }
    }

    normalized, errors = validate_schedules_dict(compatibility_shape)

    assert errors == []
    assert set(normalized.keys()) == {"general"}
    periods = normalized["general"]["periods"]
    assert set(periods.keys()) == {"morning"}
    assert periods["morning"] == {
        "active": True,
        "days": ["ALL"],
        "start_time": "00:00",
        "end_time": "00:00",
    }


@pytest.mark.unit
@pytest.mark.regression
@pytest.mark.core
def test_validate_messages_file_dict_best_effort_normalization_with_bad_rows():
    payload = {
        "messages": [
            {
                "message_id": "1",
                "message": "hey",
                "days": [],
                "time_periods": [],
                "extra": "drop",
