    assert errors, "Mixed-quality payloads should report validation issues"
    assert normalized["messages"] == [
        {
            "message_id": "1",
            "message": "hey",
            "days": ["ALL"],
            "time_periods": ["ALL"],
            "timestamp": None,
        },
        {
            "message_id": "2",
            "message": "bye",
            "days": ["Funday"],
            "time_periods": ["morning"],
            "timestamp": None,
        },
    ]
